import{_ as l,o as t,c as i,ah as e}from"./chunks/framework.DsjyFzT5.js";const r="/assets/image-7.DrbucmmD.png",o="/assets/image-8.Cv9lLIsm.png",s="/assets/image-9.Bu0hPVAp.png",n="/assets/image-2.s7J5ioo0.png",p="/assets/image-1.UskP21i_.png",h="/assets/image.JvoquUE0.png",g="/assets/image-3.D3P8CaDm.png",c="/assets/image-4.CGwQM6ti.png",u="/assets/image-6.B6hXWDQt.png",d="/assets/image-5.BhHmd9IA.png",w=JSON.parse('{"title":"Muscle Wanted","description":"","frontmatter":{"title":"Muscle Wanted","date":"2023-10-15T00:00:00.000Z","category":"life","tags":["life"]},"headers":[],"relativePath":"_post/life/jian-shen.md","filePath":"_post/life/jian-shen.md"}'),b={name:"_post/life/jian-shen.md"};function m(q,a,f,_,k,x){return t(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="muscle-wanted" tabindex="-1">Muscle Wanted <a class="header-anchor" href="#muscle-wanted" aria-label="Permalink to &quot;Muscle Wanted&quot;">​</a></h1><h2 id="基本常识" tabindex="-1">基本常识 <a class="header-anchor" href="#基本常识" aria-label="Permalink to &quot;基本常识&quot;">​</a></h2><h3 id="了解一些基础物质" tabindex="-1">了解一些基础物质 <a class="header-anchor" href="#了解一些基础物质" aria-label="Permalink to &quot;了解一些基础物质&quot;">​</a></h3><h4 id="h4-主要营养物质" tabindex="-1">h4 主要营养物质 <a class="header-anchor" href="#h4-主要营养物质" aria-label="Permalink to &quot;h4 主要营养物质&quot;">​</a></h4><ul><li><strong>蛋白质</strong>：1g蛋白质4kcal，修复肌肉的核心物质，增加肌肉量，肌肉是在超量恢复中增长的，需要蛋白质的支持，增肌人群建议吃1.3-2g/天.kg的蛋白质，可通过免疫力下降、屁多判断是否过度摄入蛋白质，日常不用担心过量摄入的问题</li><li><strong>碳水</strong>：1g碳水4kcal，身体的主要能量来源，为肌肉供能，补充肝糖原，影响胰岛素分泌，在增肌期间需要增加碳水摄入，增肌人群建议吃6-8g/天.kg的碳水，碳水的摄入量过高会导致脂肪堆积</li><li><strong>脂肪</strong>：维持激素水平，提供能量，1g脂肪9kcal，热量较高，是需要核心控制摄入的物质</li></ul><h4 id="激素类" tabindex="-1">激素类 <a class="header-anchor" href="#激素类" aria-label="Permalink to &quot;激素类&quot;">​</a></h4><ul><li><strong>皮质醇</strong>：皮质醇(压力激素)会促进蛋白质分解和脂肪储存，长期处于高水平会阻碍肌肉生长和增加腹部脂肪堆积，因此需要通过充足睡眠、适度训练强度和压力管理来控制其分泌。</li><li><strong>睾酮</strong>：一种重要的雄性激素，对于促进蛋白质合成、增加肌肉质量和力量至关重要，睾酮补充可以使身体对胰岛素的敏感性提高</li><li><strong>胰岛素</strong>：一个强大的同化激素，它能促进糖原和蛋白质合成，有助于肌肉生长和训练后恢复，但同时也会促进脂肪储存。因此在增肌期可以适当提高碳水摄入利用胰岛素作用，减脂期则需要控制胰岛素分泌。</li><li><strong>生长激素</strong>：促进肌肉生长和脂肪分解</li></ul><h4 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h4><ul><li><strong>肌酸</strong>：8分，提供快速能量，增加力量和爆发力</li><li><strong>支链氨基酸(BCAA)</strong>：7分，促进蛋白质合成，减少肌肉分解</li><li><strong>维生素D</strong>：7分，影响激素水平和肌肉功能</li><li><strong>锌</strong>：6分，影响睾酮水平和蛋白质合成</li><li><strong>镁</strong>：6分，影响能量代谢和肌肉收缩</li><li><strong>水</strong>：9分，维持新陈代谢，影响训练表现和恢复</li></ul><h3 id="能否做到同时增肌减脂" tabindex="-1">能否做到同时增肌减脂？ <a class="header-anchor" href="#能否做到同时增肌减脂" aria-label="Permalink to &quot;能否做到同时增肌减脂？&quot;">​</a></h3><blockquote><p><a href="https://www.bilibili.com/video/BV1Ne411S7nB" target="_blank" rel="noreferrer">卓叔增重</a></p></blockquote><p>增肌减重不行，增肌减脂可以</p><ol><li><p>调整运动、饮食结构，以调整激素水平</p></li><li><p>交替进行：2月增肌期，1月减脂期</p></li></ol><h3 id="如何判断有无训练效果" tabindex="-1">如何判断有无训练效果？ <a class="header-anchor" href="#如何判断有无训练效果" aria-label="Permalink to &quot;如何判断有无训练效果？&quot;">​</a></h3><ol><li>是否力竭，只要把动作做到自己没有力气了，就不会练不到位 ps：训练大肌群动作如深蹲等不建议做到力竭，孤立动作如夹胸、侧平举和弯举等可以争取做到<strong>力竭</strong></li><li><strong>渐进负荷</strong>，在可以接受的情况下每天增加一点重量，不断给肌肉压力才能有明显进步</li></ol><p><strong>按照自己的训练计划执行</strong>，尽量不要改动作，一套计划坚持三个月到半年</p><p>🏋🏻练前热身、练后拉伸 ⛹🏻练后补充糖原等，香蕉/面包/增肌粉 🚴🏻检查：肌肉酸痛，练哪哪痛</p><h3 id="瘦胖子应该如何练习" tabindex="-1">瘦胖子应该如何练习? <a class="header-anchor" href="#瘦胖子应该如何练习" aria-label="Permalink to &quot;瘦胖子应该如何练习?&quot;">​</a></h3><p>先增肌、再减脂，增肌需要热量盈余，热量盈余难免会增脂，增肌速度 &lt; 减脂速度 适当加入有氧、降低碳水 单练腹肌减不了肚子</p><h3 id="瘦子吃不够-会越练越瘦" tabindex="-1">瘦子吃不够，会越练越瘦！ <a class="header-anchor" href="#瘦子吃不够-会越练越瘦" aria-label="Permalink to &quot;瘦子吃不够，会越练越瘦！&quot;">​</a></h3><p>为什么练的很努力，却越练越瘦？ 答：肌肉是在休息的时候增长的，且遵循超量恢复，因此需要原料的支持，三分练，七分吃</p><h2 id="减脂" tabindex="-1">减脂 <a class="header-anchor" href="#减脂" aria-label="Permalink to &quot;减脂&quot;">​</a></h2><blockquote><p>参考：<a href="https://www.bilibili.com/video/BV1AM411r7z3" target="_blank" rel="noreferrer">好人松松：健身新手的减肥减脂完全手册</a></p></blockquote><p>食物摄入计算，可以用薄荷APP，也可以模仿这个表格自己做一份：<a href="https://pan.baidu.com/s/1hnFsOniea9TL-4xefgT0qg?pwd=hrss" target="_blank" rel="noreferrer">https://pan.baidu.com/s/1hnFsOniea9TL-4xefgT0qg?pwd=hrss</a></p><p>视频总结（重要表格在53分36秒有截图汇总）： 【减脂原理】 1.和体重不变相比形成10-20%热量缺口 2.应吃热量按特定的碳蛋脂配额来提供 3.碳水的日内分配讲究时机，适配力量训练</p><p>【摄入总量】（表格在视频的9分45秒） 每公斤体重的日摄入量 健身男性，碳水3-3.5g，蛋白质1.5-2g，脂肪0.8g 健身女性，碳水2.5-3g，蛋白质1.5g，脂肪0.8g 不健身的，碳水2.5-3g，蛋白质1.5g，脂肪0.8g *以上的碳水是起始量，体重不掉就减少0.3-0.5g，减脂期随体重降低，热量平衡点也在下降，所以需要递减碳水来保持热量缺口。非备赛减脂，碳水最后一般不需要低于2g。</p><p>【日内分配】（各餐安排方案在视频22分45秒） 碳水：训后餐&gt;早饭&gt;训前，碳水配额有限，其他餐少吃不吃碳水才能节约出来 蛋白质：训后要有30-50g，其他时候集中或分摊不讲究，总量符合 脂肪：训后最好20g内低脂，其他时候集中或分摊不讲究，总量符合</p><p>【食物来源】 碳水：各种主食，训后餐用高gi碳水，其他时候gi无所谓 蛋白质：纯蛋白质只有瘦肉和蛋白粉，鸡蛋、牛奶、豆制品是蛋白质和脂肪的混合物 脂肪：正常吃炒菜、鸡蛋、牛奶，固体脂肪会很占脂肪配额，吃了要正确计入</p><p>【有氧运动】 1.力量训练不用变 2.减脂前中期用饮食就很好做出热量缺口，此时有氧不重要，但在后期饮食配额比较低时候，继续减碳水会让人感到困难，这时候有氧会比较划算 3.建议休息日做40-60min长有氧，避免力量训练后做长有氧，以及做大量有氧</p><p>【常见错误】 1.食物决定论。觉得减脂就是去吃特定的食物，而搞不清楚碳蛋脂的总量和分配 2.无原则的&quot;少吃多动&quot;。热量缺口只需要比你体重不变时减少10-20%即可，一般人是三五百大卡 3.练完不吃训后餐。不要以牺牲肌肉的方式去减脂，力量训练后一定要保证训后餐来做增肌。 4.减脂期伙食难吃。改善方法：正常吃炒菜而非水煮；训后餐可以吃各种精制和甜口碳水；脂肪配额花在自己喜欢的食物上去 5.心态太急预期太高。如果积累了多年的脂肪，就需要丢更多的体重才能出效果，而不是减三五公斤就能有视觉效果的</p><p><img src="'+r+'" alt="alt text"></p><p>力量训练后升高胰岛素非常重要</p><p>吃饭方案</p><p><img src="'+o+'" alt="alt text"></p><p>例子</p><p><img src="'+s+'" alt="alt text"></p><h2 id="健身房训练" tabindex="-1">健身房训练 <a class="header-anchor" href="#健身房训练" aria-label="Permalink to &quot;健身房训练&quot;">​</a></h2><ol><li>练前热身、练后拉伸</li><li>先小重量熟悉+热身</li><li>动作注意事项：肩胛下沉、动作稳定、核心收紧</li></ol><h3 id="练前热身" tabindex="-1">练前热身 <a class="header-anchor" href="#练前热身" aria-label="Permalink to &quot;练前热身&quot;">​</a></h3><blockquote><p><a href="https://www.bilibili.com/video/BV1Mz4y1k7MG" target="_blank" rel="noreferrer">练前热身--卓叔增重</a></p></blockquote><p>慢跑5分钟</p><p>上半身</p><ul><li>拉伸胸小肌：拉3秒休息1秒 5次数</li><li>伟大拉伸：3、3、5秒</li><li>弹力带绕肩：10次</li><li>平板支撑：30秒*2</li></ul><h3 id="训练计划" tabindex="-1">训练计划 <a class="header-anchor" href="#训练计划" aria-label="Permalink to &quot;训练计划&quot;">​</a></h3><blockquote><p><a href="https://www.bilibili.com/video/BV19L4y1w7zN" target="_blank" rel="noreferrer">好人松松：三分化</a>（建议通看一遍）</p></blockquote><p><strong>【动作模式】</strong></p><p><img src="'+n+'" alt="alt text"></p><p><strong>【动作难易程度】</strong>：新手先简单的动作开始，需要慢慢过度到难的动作</p><p><img src="'+p+'" alt="alt text"></p><p><strong>【训练安排】</strong>：不要随意安排肌肉的训练组合，利用肌肉的协同效应可以节省更多的时间，比如练胸时三头、肩前束也会发力，胸练完以后可以加练肩前束、三头充分榨干</p><p>如以下三分化方案</p><p><img src="'+h+'" alt="alt text"></p><p><strong>【如何配重】</strong></p><p><img src="'+g+'" alt="alt text"></p><h3 id="胸部训练" tabindex="-1">胸部训练 <a class="header-anchor" href="#胸部训练" aria-label="Permalink to &quot;胸部训练&quot;">​</a></h3><blockquote><p><a href="https://www.bilibili.com/video/BV16a411f7XF" target="_blank" rel="noreferrer">好人松松：健身练胸教程 | 胸肌训练的原理+动作+计划+饮食</a></p></blockquote><p><strong>判断练胸位置</strong>：可通过躯干与手臂（力线方向）的夹角判断练的是胸的什么部位</p><p><img src="'+c+'" alt="alt text"></p><p><strong>动作要点</strong></p><p><img src="'+u+'" alt="alt text"></p><h4 id="杠铃卧推动作要领" tabindex="-1">杠铃卧推动作要领 <a class="header-anchor" href="#杠铃卧推动作要领" aria-label="Permalink to &quot;杠铃卧推动作要领&quot;">​</a></h4><p>三要素：握距、杠铃落点、开肘角度，共同作用，使小臂要垂直于地面</p><p><img src="'+d+'" alt="alt text"></p><h4 id="热身" tabindex="-1">热身 <a class="header-anchor" href="#热身" aria-label="Permalink to &quot;热身&quot;">​</a></h4><ul><li>胸椎：胸椎在泡沫轴上滚动1-2分钟</li><li>肩胛下沉：弹力带颈后起落，8-15次 * 2组</li><li>肩袖肌群：外展+推举 8-15次 * 2组</li><li>夹胸： 8-12次 * 3-4组</li></ul><h3 id="其他练习动作参考" tabindex="-1">其他练习动作参考 <a class="header-anchor" href="#其他练习动作参考" aria-label="Permalink to &quot;其他练习动作参考&quot;">​</a></h3><ul><li><a href="https://b23.tv/zZBW6FA" target="_blank" rel="noreferrer">腿、臀、小腿、核心</a>：</li><li><a href="https://b23.tv/sfWbi4M" target="_blank" rel="noreferrer">居家版4肢练习</a></li></ul><h2 id="问题记录" tabindex="-1">问题记录 <a class="header-anchor" href="#问题记录" aria-label="Permalink to &quot;问题记录&quot;">​</a></h2><h3 id="肩弱" tabindex="-1">肩弱 <a class="header-anchor" href="#肩弱" aria-label="Permalink to &quot;肩弱&quot;">​</a></h3><ol><li>健身房8个月左右，肩部力量弱，哑铃卧推30kg做组，哑铃推肩只能14kg做组，有种有劲使不出的感觉</li></ol><p><strong>现在</strong>，一周五 || 六练（除非特殊备注，每个动作默认都是4组），各个动作按练的先后顺序给出</p><ul><li>背 + 肩后束 + 二头 <ul><li>引体向上、宽距高位下拉、宽距绳索划船</li><li>坐姿飞鸟、面拉（偶尔）</li><li>杠铃弯举、哑铃弯举</li></ul></li><li>胸 + 肩前束、肩中束 + 三头 <ul><li>哑铃平板卧推 * 5组、哑铃上斜卧推、双杠臂屈伸 || 坐姿下斜推胸</li><li>坐姿推肩（史密斯 || 哑铃）、龙门架飞鸟、哑铃侧平举</li><li>直杆下压、绳索下压</li></ul></li><li>腿 + 腹肌 <ul><li>哈克深蹲、腿外展、腿内收、坐姿腿屈伸（偶尔）</li><li>悬垂举腿、龙门架弯举、坐姿卷腹、平板支撑</li></ul></li></ul><p><strong>调整方案</strong>：</p><p>前三天同上</p><ul><li>背 + 肩后束 + 二头</li><li>胸 + 肩前束、肩中束 + 三头</li><li>腿 + 腹肌</li></ul><p>后三天：</p><ul><li>背 + 二头 <ul><li>引体向上、宽距高位下拉、窄距绳索划船、哑铃划船 || T杆划船</li><li>杠铃弯举、哑铃弯举</li></ul></li><li>胸 + 三头 <ul><li>哑铃平板卧推、哑铃上斜卧推、双杠臂屈伸 || 坐姿下斜推胸、夹胸</li><li>直杆下压、绳索下压</li></ul></li><li>腹肌 + 肩 <ul><li>坐姿推肩（史密斯 || 哑铃）、龙门架飞鸟、哑铃侧平举 、坐姿飞鸟、面拉（偶尔）、阿洛德推举</li><li>悬垂举腿、龙门架弯举、坐姿卷腹、平板支撑</li></ul></li></ul>',77)])])}const B=l(b,[["render",m]]);export{w as __pageData,B as default};
